import { Contact, Category } from '../types';
import { DEFAULT_CATEGORIES, MOCK_DATA } from '../constants';

const CONTACTS_KEY = 'pr_contacts_data';
const CATEGORIES_KEY = 'pr_categories_data';

export const getContacts = (): Contact[] => {
  try {
    const data = localStorage.getItem(CONTACTS_KEY);
    if (!data) {
      // Initialize with mock data if empty
      localStorage.setItem(CONTACTS_KEY, JSON.stringify(MOCK_DATA));
      return MOCK_DATA as Contact[];
    }
    return JSON.parse(data);
  } catch (error) {
    console.error("Error loading contacts", error);
    return [];
  }
};

export const saveContact = (contact: Contact): void => {
  const contacts = getContacts();
  const existingIndex = contacts.findIndex(c => c.id === contact.id);

  if (existingIndex >= 0) {
    contacts[existingIndex] = contact;
  } else {
    contacts.push(contact);
  }

  localStorage.setItem(CONTACTS_KEY, JSON.stringify(contacts));
};

export const deleteContact = (id: string): void => {
  const contacts = getContacts();
  const newContacts = contacts.filter(c => c.id !== id);
  localStorage.setItem(CONTACTS_KEY, JSON.stringify(newContacts));
};

export const getCategories = (): Category[] => {
  try {
    const data = localStorage.getItem(CATEGORIES_KEY);
    if (!data) {
      const defaults = DEFAULT_CATEGORIES.map(c => ({ id: crypto.randomUUID(), name: c }));
      localStorage.setItem(CATEGORIES_KEY, JSON.stringify(defaults));
      return defaults;
    }
    return JSON.parse(data);
  } catch (error) {
    return [];
  }
};

export const addCategory = (name: string): Category => {
  const categories = getCategories();
  const newCat = { id: crypto.randomUUID(), name };
  categories.push(newCat);
  localStorage.setItem(CATEGORIES_KEY, JSON.stringify(categories));
  return newCat;
};

export const deleteCategory = (id: string): void => {
  const categories = getCategories();
  const newCats = categories.filter(c => c.id !== id);
  localStorage.setItem(CATEGORIES_KEY, JSON.stringify(newCats));
};

// Function to generate CSV matching the Google Sheet structure
export const exportToCSV = (): string => {
  const contacts = getContacts();
  const headers = [
    "ชื่อ-นามสกุล", "ประเภทของข้อมูล", "ตำแหน่ง", "หน่วยงาน", "เบอร์โทรศัพท์", 
    "e-mail", "เลขที่", "ซอย", "หมู่ที่", "ถนน", 
    "ตำบล/แขวง", "อำเภอ/เขต", "จังหวัด", "รหัสไปรษณีย์", "LINK"
  ];

  const rows = contacts.map(c => [
    c.name,
    c.type,
    c.position,
    c.organization,
    c.phone,
    c.email,
    c.address.no,
    c.address.soi,
    c.address.moo,
    c.address.road,
    c.address.subdistrict,
    c.address.district,
    c.address.province,
    c.address.zipcode,
    c.link
  ]);

  const csvContent = [
    headers.join(","),
    ...rows.map(row => row.map(cell => `"${(cell || '').replace(/"/g, '""')}"`).join(","))
  ].join("\n");

  return csvContent;
};

import React from 'react';
import { clsx } from 'clsx';
import { twMerge } from 'tailwind-merge';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  className, 
  variant = 'primary', 
  size = 'md',
  isLoading,
  disabled,
  ...props 
}) => {
  const baseStyles = 'inline-flex items-center justify-center rounded-lg font-medium transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2';

  const variants = {
    primary: 'bg-primary text-white hover:bg-blue-800 focus:ring-blue-500',
    secondary: 'bg-white text-gray-700 border border-gray-300 hover:bg-gray-50 focus:ring-gray-500',
    danger: 'bg-red-600 text-white hover:bg-red-700 focus:ring-red-500',
    ghost: 'bg-transparent text-gray-600 hover:bg-gray-100 hover:text-gray-900',
  };

  const sizes = {
    sm: 'px-3 py-1.5 text-sm',
    md: 'px-4 py-2 text-base',
    lg: 'px-6 py-3 text-lg',
  };

  return (
    <button
      className={twMerge(baseStyles, variants[variant], sizes[size], className)}
      disabled={disabled || isLoading}
      {...props}
    >
      {isLoading ? (
        <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-current" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
        </svg>
      ) : null}
      {children}
    </button>
  );
};

import React, { forwardRef } from 'react';
import { clsx } from 'clsx';
import { twMerge } from 'tailwind-merge';

interface InputProps extends React.InputHTMLAttributes<HTMLInputElement> {
  label?: string;
  error?: string;
}

export const Input = forwardRef<HTMLInputElement, InputProps>(({ label, error, className, ...props }, ref) => {
  return (
    <div className="w-full">
      {label && (
        <label className="block text-sm font-medium text-gray-700 mb-1">
          {label}
        </label>
      )}
      <input
        ref={ref}
        className={twMerge(
          "block w-full rounded-md border-gray-300 shadow-sm focus:border-primary focus:ring-primary sm:text-sm border p-2",
          error && "border-red-500 focus:border-red-500 focus:ring-red-500",
          className
        )}
        {...props}
      />
      {error && <p className="mt-1 text-sm text-red-600">{error}</p>}
    </div>
  );
});

