import React, { useState, useEffect } from 'react';
import { Contact, Category } from '../types';
import { Button } from './Button';
import { Input } from './Input';
import { Save, X } from 'lucide-react';

interface ContactFormProps {
  initialData?: Contact | null;
  categories: Category[];
  onSave: (contact: Contact) => void;
  onCancel: () => void;
}

export const ContactForm: React.FC<ContactFormProps> = ({ initialData, categories, onSave, onCancel }) => {
  const [formData, setFormData] = useState<Contact>({
    id: crypto.randomUUID(),
    name: '',
    type: categories[0]?.name || '',
    position: '',
    organization: '',
    phone: '',
    email: '',
    address: {
      no: '', soi: '', moo: '', road: '', subdistrict: '', district: '', province: '', zipcode: ''
    },
    link: '',
    createdAt: Date.now()
  });

  useEffect(() => {
    if (initialData) {
      setFormData(initialData);
    } else if (categories.length > 0) {
        setFormData(prev => ({ ...prev, type: categories[0].name }));
    }
  }, [initialData, categories]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    if (name.startsWith('address.')) {
      const addressField = name.split('.')[1];
      setFormData(prev => ({
        ...prev,
        address: { ...prev.address, [addressField]: value }
      }));
    } else {
      setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave(formData);
  };

  return (
    <form onSubmit={handleSubmit} className="bg-white rounded-xl shadow-md p-6 max-w-4xl mx-auto">
      <div className="flex justify-between items-center mb-6 pb-4 border-b">
        <h2 className="text-xl font-bold text-gray-800">
          {initialData ? 'แก้ไขข้อมูล' : 'เพิ่มข้อมูลใหม่'}
        </h2>
        <button type="button" onClick={onCancel} className="text-gray-400 hover:text-gray-600">
          <X size={24} />
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="space-y-4">
          <h3 className="text-sm font-semibold text-gray-500 uppercase tracking-wider mb-2">ข้อมูลทั่วไป</h3>
          <Input 
            label="ชื่อ-นามสกุล" 
            name="name" 
            value={formData.name} 
            onChange={handleChange} 
            required 
            placeholder="เช่น นายสมชาย ใจดี"
          />

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">ประเภทของข้อมูล</label>
            <select
              name="type"
              value={formData.type}
              onChange={handleChange}
              className="block w-full rounded-md border-gray-300 shadow-sm focus:border-primary focus:ring-primary sm:text-sm border p-2"
            >
              {categories.map(cat => (
                <option key={cat.id} value={cat.name}>{cat.name}</option>
              ))}
            </select>
          </div>

          <Input label="ตำแหน่ง" name="position" value={formData.position} onChange={handleChange} />
          <Input label="หน่วยงาน" name="organization" value={formData.organization} onChange={handleChange} />
          <Input label="เบอร์โทรศัพท์" name="phone" value={formData.phone} onChange={handleChange} />
          <Input label="E-mail" name="email" type="email" value={formData.email} onChange={handleChange} />
          <Input label="LINK (URL)" name="link" value={formData.link} onChange={handleChange} placeholder="https://..." />
        </div>

        <div className="space-y-4">
          <h3 className="text-sm font-semibold text-gray-500 uppercase tracking-wider mb-2">ที่อยู่</h3>
          <div className="grid grid-cols-2 gap-4">
            <Input label="เลขที่" name="address.no" value={formData.address.no} onChange={handleChange} />
            <Input label="หมู่ที่" name="address.moo" value={formData.address.moo} onChange={handleChange} />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <Input label="ซอย" name="address.soi" value={formData.address.soi} onChange={handleChange} />
            <Input label="ถนน" name="address.road" value={formData.address.road} onChange={handleChange} />
          </div>
          <Input label="ตำบล/แขวง" name="address.subdistrict" value={formData.address.subdistrict} onChange={handleChange} />
          <Input label="อำเภอ/เขต" name="address.district" value={formData.address.district} onChange={handleChange} />
          <div className="grid grid-cols-2 gap-4">
            <Input label="จังหวัด" name="address.province" value={formData.address.province} onChange={handleChange} />
            <Input label="รหัสไปรษณีย์" name="address.zipcode" value={formData.address.zipcode} onChange={handleChange} />
          </div>
        </div>
      </div>

      <div className="mt-8 pt-4 border-t flex justify-end space-x-3">
        <Button type="button" variant="secondary" onClick={onCancel}>ยกเลิก</Button>
        <Button type="submit" variant="primary">
          <Save className="w-4 h-4 mr-2" />
          บันทึกข้อมูล
        </Button>
      </div>
    </form>
  );
};

import React, { useState } from 'react';
import { Category } from '../types';
import { Button } from './Button';
import { Input } from './Input';
import { Trash2, Plus, Tag } from 'lucide-react';

interface CategoryManagerProps {
  categories: Category[];
  onAdd: (name: string) => void;
  onDelete: (id: string) => void;
}

export const CategoryManager: React.FC<CategoryManagerProps> = ({ categories, onAdd, onDelete }) => {
  const [newCategory, setNewCategory] = useState('');

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (newCategory.trim()) {
      onAdd(newCategory.trim());
      setNewCategory('');
    }
  };

  return (
    <div className="max-w-2xl mx-auto bg-white rounded-xl shadow-md p-6">
      <div className="flex items-center space-x-3 mb-6">
        <div className="p-3 bg-blue-100 rounded-lg text-primary">
          <Tag size={24} />
        </div>
        <div>
          <h2 className="text-xl font-bold text-gray-800">จัดการหมวดหมู่ข้อมูล</h2>
          <p className="text-sm text-gray-500">เพิ่มหรือลบประเภทของข้อมูลสื่อมวลชน</p>
        </div>
      </div>

      <form onSubmit={handleAdd} className="flex gap-2 mb-6">
        <Input 
          placeholder="ชื่อหมวดหมู่ใหม่..." 
          value={newCategory}
          onChange={(e) => setNewCategory(e.target.value)}
          className="flex-1"
        />
        <Button type="submit" disabled={!newCategory.trim()}>
          <Plus size={18} className="mr-2" />
          เพิ่ม
        </Button>
      </form>

      <div className="space-y-2">
        {categories.map((category) => (
          <div 
            key={category.id} 
            className="flex items-center justify-between p-3 bg-gray-50 rounded-lg border border-gray-100 hover:border-gray-300 transition-colors"
          >
            <span className="font-medium text-gray-700">{category.name}</span>
            <button 
              onClick={() => onDelete(category.id)}
              className="text-gray-400 hover:text-red-600 transition-colors p-1"
              title="ลบ"
            >
              <Trash2 size={18} />
            </button>
          </div>
        ))}
        {categories.length === 0 && (
          <div className="text-center py-8 text-gray-400">
            ยังไม่มีหมวดหมู่
          </div>
        )}
      </div>
    </div>
  );
};

import React from 'react';
import { Contact } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, BarChart, Bar, XAxis, YAxis, CartesianGrid, Legend } from 'recharts';

interface StatsProps {
  contacts: Contact[];
}

export const Stats: React.FC<StatsProps> = ({ contacts }) => {
  // Aggregate data by Type
  const typeData = contacts.reduce((acc, curr) => {
    acc[curr.type] = (acc[curr.type] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  const pieData = Object.entries(typeData).map(([name, value]) => ({ name, value }));

  // Aggregate by Province (Top 5)
  const provinceDataRaw = contacts.reduce((acc, curr) => {
    const prov = curr.address.province || 'ไม่ระบุ';
    acc[prov] = (acc[prov] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  const barData = Object.entries(provinceDataRaw)
    .map(([name, value]) => ({ name, value }))
    .sort((a, b) => b.value - a.value)
    .slice(0, 5);

  const COLORS = ['#0f4c81', '#e1ad01', '#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#8884d8'];

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-md">
          <h3 className="text-lg font-bold text-gray-800 mb-4">จำนวนตามประเภทสื่อ</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={pieData}
                  cx="50%"
                  cy="50%"
                  labelLine={false}
                  label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}
                  outerRadius={80}
                  fill="#8884d8"
                  dataKey="value"
                >
                  {pieData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-md">
          <h3 className="text-lg font-bold text-gray-800 mb-4">จังหวัดที่มีผู้ติดต่อมากที่สุด (Top 5)</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={barData} layout="vertical">
                <CartesianGrid strokeDasharray="3 3" horizontal={false} />
                <XAxis type="number" allowDecimals={false} />
                <YAxis dataKey="name" type="category" width={100} tick={{fontSize: 12}} />
                <Tooltip />
                <Bar dataKey="value" fill="#0f4c81" radius={[0, 4, 4, 0]} name="จำนวน" />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      <div className="bg-white p-6 rounded-xl shadow-md">
        <div className="flex items-center justify-between">
          <div>
            <h3 className="text-lg font-bold text-gray-800">สรุปภาพรวม</h3>
            <p className="text-gray-500">ข้อมูลทั้งหมดในระบบ</p>
          </div>
          <div className="text-4xl font-bold text-primary">{contacts.length} <span className="text-base font-normal text-gray-500">รายการ</span></div>
        </div>
      </div>
    </div>
  );
};

