                        </button>
                      </div>
                    </div>

                    <h3 className="text-lg font-bold text-gray-900 mb-1">{contact.name}</h3>
                    <p className="text-gray-600 text-sm mb-4">{contact.position} @ {contact.organization}</p>

                    <div className="space-y-2 text-sm text-gray-500">
                      <div className="flex items-center">
                        <Phone size={14} className="mr-2 text-gray-400" />
                        {contact.phone || '-'}
                      </div>
                      <div className="flex items-center">
                        <Mail size={14} className="mr-2 text-gray-400" />
                        <span className="truncate">{contact.email || '-'}</span>
                      </div>
                      <div className="flex items-start">
                        <MapPin size={14} className="mr-2 mt-1 text-gray-400 flex-shrink-0" />
                        <span className="line-clamp-2">
                          {[contact.address.subdistrict, contact.address.district, contact.address.province].filter(Boolean).join(', ')}
                        </span>
                      </div>
                    </div>
                  </div>

                  {contact.link && (
                    <a 
                      href={contact.link.startsWith('http') ? contact.link : `https://${contact.link}`} 
                      target="_blank" 
                      rel="noreferrer"
                      className="block bg-gray-50 p-3 text-center text-sm text-blue-600 font-medium hover:bg-blue-50 transition-colors border-t border-gray-100"
                    >
                      เยี่ยมชมเว็บไซต์
                    </a>
                  )}
                </div>
              ))}

              {!isLoading && filteredContacts.length === 0 && (
                <div className="col-span-full text-center py-12 text-gray-500 bg-white rounded-xl border border-dashed border-gray-300">
                  <Users size={48} className="mx-auto mb-3 opacity-20" />
                  <p>ไม่พบข้อมูลผู้ติดต่อ</p>
                </div>
              )}
            </div>

            {!isLoading && filteredContacts.length === 0 && (
               <div className="text-left">
                  <a 
                    href={GOOGLE_SHEET_URL} 
                    target="_blank" 
                    rel="noreferrer"
                    className="text-primary hover:underline text-base"
                  >
                    ข้อมูลจากGoogle Sheet ยังไม่แสดง
                  </a>
               </div>
            )}

          </div>
        )}

        {view === 'add' && (
          <ContactForm 
            categories={categories} 
            onSave={handleSaveContact} 
            onCancel={() => { setView('dashboard'); setEditingContact(null); }}
            initialData={editingContact}
          />
        )}

        {view === 'categories' && (
          <CategoryManager 
            categories={categories} 
            onAdd={handleAddCategory} 
            onDelete={handleDeleteCategory} 
          />
        )}

        {view === 'analytics' && (
          <Stats contacts={contacts} />
        )}

      </main>
    </div>
  );
};

export default App;

export const DEFAULT_CATEGORIES = [
  'สื่อโทรทัศน์',
  'สื่อสิ่งพิมพ์',
  'สื่อออนไลน์',
  'วิทยุ',
  'Influencer',
  'Partner',
  'หน่วยงานราชการ'
];

export const GOOGLE_SHEET_URL = "https://docs.google.com/spreadsheets/d/1rhMfB_nmWUNXdx6ceZhSjQusNG04EsS3u4SCtDzmaso/edit?gid=1170499384#gid=1170499384";

export const API_ENDPOINT = "https://script.google.com/macros/s/AKfycbwvKcKSwczsL-pobV7L3G6yOXpY4c8yP3hwLWsGhbIARw9Dmg7fXVFhFQjcGWRIrhtQ/exec";

export const MOCK_DATA = [];

payload.text:
นี่คือ **Google Apps Script** ที่ออกแบบมาเพื่อรองรับระบบ CRUD (Create, Read, Update, Delete) เต็มรูปแบบสำหรับโปรเจกต์ของคุณครับ

คุณต้องนำ Code นี้ไปวางใน Google Apps Script Editor ของ Google Sheet นั้นครับ

### ขั้นตอนการติดตั้ง Google Apps Script

1. เปิด Google Sheet ของคุณ
2. ไปที่เมนู **Extensions (ส่วนขยาย)** > **Apps Script**
3. ลบ Code เก่าทั้งหมด แล้ววาง Code ด้านล่างนี้ลงไป
4. กด **Save** (รูปแผ่นดิสก์)
5. กดปุ่ม **Deploy (การทำให้ใช้งานได้)** > **New deployment (การทำให้ใช้งานได้รายการใหม่)**
6. เลือกประเภทเป็น **Web app**
   - **Description:** ใส่ชื่ออะไรก็ได้
   - **Execute as:** เลือก **Me (ฉัน)** (สำคัญมาก)
   - **Who has access:** เลือก **Anyone (ทุกคน)** (สำคัญมาก เพื่อให้ Web App เข้าถึงได้)
7. กด **Deploy** และคัดลอก **Web App URL** ที่ได้
8. นำ URL นั้นไปแทนที่ในไฟล์ `constants.ts` ของโปรเจกต์ React

---

### Google Apps Script Code (`Code.gs`)

```javascript
// ตั้งค่า ID ของ Spreadsheet และ GID ของ Sheet ที่ต้องการใช้งาน
const SPREADSHEET_ID = '1rhMfB_nmWUNXdx6ceZhSjQusNG04EsS3u4SCtDzmaso';
const SHEET_GID = 1170499384; // มาจาก URL parameter gid=...

function doGet(e) {
  return handleRequest(e);
}

function doPost(e) {
  return handleRequest(e);
}

function handleRequest(e) {
  const lock = LockService.getScriptLock();
  lock.tryLock(10000); // ป้องกันการเขียนข้อมูลทับกันพร้อมกัน

  try {
    const sheet = getSheetById(SHEET_GID);

    // กรณีเป็นการอ่านข้อมูล (GET)
    if (!e.postData) {
      const data = getData(sheet);
      return createJSONOutput({ status: 'success', data: data });
    }

    // กรณีเป็นการเขียน/แก้ไข/ลบข้อมูล (POST)
    const params = JSON.parse(e.postData.contents);
    const action = params.action || 'create'; // default action

    if (action === 'create') {
      const newRow = createRow(sheet, params);
      return createJSONOutput({ status: 'success', message: 'Created successfully', row: newRow });
    } 
    else if (action === 'update') {
      updateRow(sheet, params);
      return createJSONOutput({ status: 'success', message: 'Updated successfully' });
    } 
    else if (action === 'delete') {
      deleteRow(sheet, params);
      return createJSONOutput({ status: 'success', message: 'Deleted successfully' });
    }

    return createJSONOutput({ status: 'error', message: 'Unknown action' });

  } catch (error) {
    return createJSONOutput({ status: 'error', message: error.toString() });
  } finally {
    lock.releaseLock();
  }
}

// ฟังก์ชันช่วยหา Sheet จาก GID
function getSheetById(gid) {
  const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
  const sheets = ss.getSheets();
  for (let i = 0; i < sheets.length; i++) {
    if (sheets[i].getSheetId() === gid) {
      return sheets[i];
    }
  }
  throw new Error("Sheet with GID " + gid + " not found.");
}

// ฟังก์ชันอ่านข้อมูล
function getData(sheet) {
  const lastRow = sheet.getLastRow();
  if (lastRow < 2) return []; // ไม่มีข้อมูล (มีแค่ Header)

  const range = sheet.getRange(2, 1, lastRow - 1, sheet.getLastColumn());
  const values = range.getValues();
  const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];

  // แปลง Array of Arrays เป็น Array of Objects
  return values.map((row, index) => {
    let obj = {
      // ส่ง rowId กลับไปด้วย (บวก 2 เพราะ index เริ่ม 0 และ header กินไป 1 แถว)
      rowId: index + 2 
    };
    headers.forEach((header, i) => {
      obj[header] = row[i];
    });
    return obj;
  });
}

// ฟังก์ชันเพิ่มข้อมูล
function createRow(sheet, data) {
  const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
  const rowData = headers.map(header => data[header] || '');
  sheet.appendRow(rowData);
  return sheet.getLastRow();
}

// ฟังก์ชันอัพเดทข้อมูล
function updateRow(sheet, params) {
  const rowIndex = parseInt(params.rowId);
  const data = params.data; // ข้อมูลใหม่

  if (isNaN(rowIndex) || rowIndex < 2) throw new Error("Invalid Row ID");

  const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
  const rowData = headers.map(header => data[header] || '');

  // เขียนทับแถวเดิม
  sheet.getRange(rowIndex, 1, 1, rowData.length).setValues([rowData]);
}

// ฟังก์ชันลบข้อมูล
function deleteRow(sheet, params) {
  const rowIndex = parseInt(params.rowId);
  if (isNaN(rowIndex) || rowIndex < 2) throw new Error("Invalid Row ID");

  sheet.deleteRow(rowIndex);
}

function createJSONOutput(data) {
  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}
```

