    DataService.addCategory(name);
    setCategories(DataService.getCategories());
  };

  const handleDeleteCategory = (id: string) => {
    if (confirm('ยืนยันการลบหมวดหมู่?')) {
      DataService.deleteCategory(id);
      setCategories(DataService.getCategories());
    }
  };

