                />
                <Bar dataKey="value" fill="#0f4c81" radius={[0, 4, 4, 0]} barSize={20}>
                    {stats.provinceData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={index < 3 ? '#0f4c81' : '#94a3b8'} />
                    ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
