                  <select 
                    className="p-2 border border-gray-300 rounded-lg bg-white w-full md:w-auto md:min-w-[200px]"
                    value={selectedCategoryFilter}
                    onChange={(e) => setSelectedCategoryFilter(e.target.value)}
