                            </span>
                          </td>
                          <td className="px-6 py-4">
                            <div className="text-sm text-gray-900">{contact.position}</div>
                            <div className="text-sm text-gray-500">{contact.organization}</div>
                          </td>
                          <td className="px-6 py-4">
                            <div className="text-sm text-gray-900 flex items-center gap-1.5 mb-1">
                              <Phone size={14} className="text-gray-400 flex-shrink-0" />
                              {contact.phone || '-'}
                            </div>
                            <div className="text-sm text-gray-500 flex items-center gap-1.5">
                              <Mail size={14} className="text-gray-400 flex-shrink-0" />
                              <span className="truncate max-w-[150px]">{contact.email || '-'}</span>
                            </div>
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                            {contact.address.province}
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                            <div className="flex justify-end gap-3">
                                {contact.link && (
                                  <a 
                                    href={contact.link.startsWith('http') ? contact.link : `https://${contact.link}`} 
                                    target="_blank" 
                                    rel="noreferrer"
                                    className="text-gray-400 hover:text-blue-600 transition-colors"
                                    title="เยี่ยมชมเว็บไซต์"
                                  >
                                    <ExternalLink size={18} />
                                  </a>
                                )}
                                <button 
                                  onClick={() => handleViewContact(contact)} 
                                  className="text-gray-400 hover:text-blue-600 transition-colors"
                                  title="ดูรายละเอียด"
                                >
                                  <Eye size={18}/>
                                </button>
                                {userRole === 'editor' && (
                                    <>
                                        <button 
                                            onClick={() => handleEditContact(contact)} 
                                            className="text-gray-400 hover:text-blue-600 transition-colors"
                                            title="แก้ไข"
                                        >
                                            <Edit size={18}/>
                                        </button>
                                        <button 
                                            onClick={() => handleDeleteContact(contact.id)} 
                                            className="text-gray-400 hover:text-red-600 transition-colors"
                                            title="ลบ"
                                        >
                                            <Trash2 size={18}/>
                                        </button>
                                    </>
                                )}
                            </div>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}

              {!isLoading && filteredContacts.length === 0 && (
                <div className="col-span-full text-center py-12 text-gray-500 bg-white rounded-xl border border-dashed border-gray-300">
                  <Users size={48} className="mx-auto mb-3 opacity-20" />
                  <p>ไม่พบข้อมูลผู้ติดต่อ</p>
                </div>
              )}

              {!isLoading && filteredContacts.length === 0 && userRole === 'editor' && (
                 <div className="text-left">
                    <a 
                      href={GOOGLE_SHEET_URL} 
                      target="_blank" 
                      rel="noreferrer"
                      className="text-primary hover:underline text-base"
                    >
                      ข้อมูลจากGoogle Sheet ยังไม่แสดง
                    </a>
                 </div>
              )}

            </div>
          )}

          {view === 'add' && (
            <ContactForm 
              categories={categories} 
              onSave={handleSaveContact} 
              onCancel={() => { setView('dashboard'); setEditingContact(null); }}
              initialData={editingContact}
            />
          )}

          {view === 'categories' && (
            <CategoryManager 
              categories={categories} 
              onAdd={handleAddCategory} 
              onDelete={handleDeleteCategory} 
            />
          )}

          {view === 'analytics' && (
            <Stats contacts={contacts} />
          )}

          {view === 'details' && viewingContact && (
             <ContactDetail 
                contact={viewingContact}
                onBack={() => { setView('dashboard'); setViewingContact(null); }}
                onEdit={(c) => { handleEditContact(c); }}
                onDelete={(id) => { handleDeleteContact(id); setView('dashboard'); }}
                readOnly={userRole !== 'editor'}
             />
          )}

        </main>
      </div>
    </div>
  );
};

export default App;

export interface Contact {
  id: string;
  name: string; // ชื่อ-นามสกุล
  type: string; // ประเภทของข้อมูล
  position: string; // ตำแหน่ง
  organization: string; // หน่วยงาน
  phone: string; // เบอร์โทรศัพท์
  email: string; // e-mail
  address: {
    no: string; // เลขที่
    soi: string; // ซอย
    moo: string; // หมู่ที่
    road: string; // ถนน
    subdistrict: string; // ตำบล/แขวง
    district: string; // อำเภอ/เขต
    province: string; // จังหวัด
    zipcode: string; // รหัสไปรษณีย์
  };
  link: string; // LINK
  createdAt: number;
}

export interface Category {
  id: string;
  name: string;
}

