    "e-mail", "เลขที่", "ซอย", "หมู่ที่", "ถนน", 
    "ตำบล/แขวง", "อำเภอ/เขต", "จังหวัด", "รหัสไปรษณีย์", "LINK"
  ];

  const rows = contacts.map(c => [
    c.name,
