            <tbody className="bg-white divide-y divide-gray-200">
                {filteredLogs.map((log) => (
                <tr key={log.id} className="hover:bg-gray-50">
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                        {formatDate(log.timestamp)}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                        <div className="flex flex-col">
                            <span className="text-sm font-medium text-gray-900">{log.userName}</span>
                            <span className="text-xs text-gray-400 capitalize">{log.userRole}</span>
                        </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                        <span className={`px-2 py-1 inline-flex text-xs leading-5 font-semibold rounded-full ${getActionColor(log.action)}`}>
                            {log.action}
                        </span>
                    </td>
                    <td className="px-6 py-4 text-sm text-gray-600">
                        {log.details}
                    </td>
                </tr>
                ))}
                {filteredLogs.length === 0 && (
                    <tr>
                        <td colSpan={4} className="px-6 py-12 text-center text-gray-500">
                            ไม่พบประวัติการใช้งาน
                        </td>
                    </tr>
                )}
            </tbody>
            </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Button } from './Button';
import { Input } from './Input';
import { Users, Shield, UserCog, Lock, Info } from 'lucide-react';
import { User, UserRole } from '../types';
import * as DataService from '../services/dataService';

interface LoginScreenProps {
  onLogin: (user: User) => void;
}

export const LoginScreen: React.FC<LoginScreenProps> = ({ onLogin }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    const cleanUsername = username.trim();

    // Use DataService to authenticate
    setTimeout(() => {
      const user = DataService.authenticateUser(cleanUsername, password);

      if (user) {
        onLogin(user);
      } else {
        setError('ชื่อผู้ใช้งานหรือรหัสผ่านไม่ถูกต้อง');
        setIsLoading(false);
      }
    }, 600); // Simulate network delay slightly for better UX
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-900 via-primary to-blue-800 flex items-center justify-center p-4">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-4xl overflow-hidden flex flex-col md:flex-row animate-in fade-in zoom-in-95 duration-500">

        {/* Left Side - Info */}
        <div className="md:w-1/2 bg-blue-50 p-8 flex flex-col justify-center items-center text-center border-b md:border-b-0 md:border-r border-blue-100">
          <div className="bg-primary/10 p-4 rounded-full mb-6">
            <Users size={48} className="text-primary" />
          </div>
          <h1 className="text-3xl font-bold text-primary mb-2">PR Manager</h1>
          <p className="text-gray-600 mb-8">ระบบบริหารจัดการฐานข้อมูลสื่อมวลชน<br/>และเครือข่ายประชาสัมพันธ์</p>

          <div className="space-y-4 w-full max-w-xs text-left text-sm text-gray-500">
            <div className="flex items-center gap-3 p-3 bg-white rounded-lg shadow-sm">
              <Shield className="text-green-600" size={20} />
              <div>
                <span className="font-semibold text-gray-900 block">Viewer</span>
                เข้าดูข้อมูลและสถิติ
              </div>
            </div>
            <div className="flex items-center gap-3 p-3 bg-white rounded-lg shadow-sm">
              <UserCog className="text-orange-500" size={20} />
              <div>
                <span className="font-semibold text-gray-900 block">Editor</span>
                จัดการรายชื่อผู้ติดต่อ
              </div>
            </div>
            <div className="flex items-center gap-3 p-3 bg-white rounded-lg shadow-sm">
              <Lock className="text-red-500" size={20} />
              <div>
                <span className="font-semibold text-gray-900 block">Admin</span>
                จัดการระบบและตั้งค่า
              </div>
            </div>
          </div>
        </div>

        {/* Right Side - Login Form */}
        <div className="md:w-1/2 p-8 md:p-12 flex flex-col justify-center bg-white">
          <h2 className="text-2xl font-bold text-gray-800 mb-6">เข้าสู่ระบบ</h2>

          <form onSubmit={handleLogin} className="space-y-5">
            <Input 
              label="ชื่อผู้ใช้งาน (Username)"
              placeholder="กรอกชื่อผู้ใช้งาน..."
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              disabled={isLoading}
            />
            <Input 
              label="รหัสผ่าน (Password)"
              type="password"
              placeholder="••••••••"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              disabled={isLoading}
            />

            {error && (
              <div className="p-3 bg-red-50 text-red-600 text-sm rounded-lg border border-red-100 flex items-center">
                <span className="mr-2">⚠️</span> {error}
              </div>
            )}

            <Button type="submit" className="w-full" isLoading={isLoading}>
              เข้าสู่ระบบ
            </Button>
          </form>

          <div className="mt-8 p-4 bg-gray-50 rounded-lg border border-gray-100 flex items-start gap-3">
             <Info className="text-blue-500 flex-shrink-0 mt-0.5" size={18} />
             <div className="text-xs text-gray-500">
                <p className="font-semibold text-gray-700 mb-1">ไม่มีบัญชีผู้ใช้งาน?</p>
                <p>กรุณาติดต่อผู้ดูแลระบบ (Admin) เพื่อทำการสร้างบัญชีและรับรหัสผ่านสำหรับเข้าใช้งาน</p>
             </div>
          </div>

          <p className="mt-6 text-xs text-center text-gray-400">
             © 2024 PR Contact Manager System
          </p>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Contact, Category, ViewState, UserRole, User } from './types';
import * as DataService from './services/dataService';
import { ContactForm } from './components/ContactForm';
import { CategoryManager } from './components/CategoryManager';
import { Stats } from './components/Stats';
import { ContactDetail } from './components/ContactDetail';
import { Button } from './components/Button';
import { LoginScreen } from './components/LoginScreen';
import { UserManager } from './components/UserManager';
import { ActivityLogViewer } from './components/ActivityLogViewer';
import { GOOGLE_SHEET_URL } from './constants';
import { 
  LayoutDashboard, 
  Plus, 
  Users, 
  Settings, 
  Search, 
  Download, 
  ExternalLink,
  MapPin,
  Phone,
  Mail,
  Edit,
  Trash2,
  PieChart,
  RefreshCw,
  LayoutList,
  LayoutGrid,
  Eye,
  Menu,
  X,
  LogOut,
  Shield,
  ShieldCheck,
  Lock,
  UserCog,
  History
} from 'lucide-react';

const App: React.FC = () => {
  // Auth State
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [userRole, setUserRole] = useState<UserRole>('viewer');
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  const [view, setView] = useState<ViewState>('dashboard');
  const [viewMode, setViewMode] = useState<'grid' | 'table'>('table'); 
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [editingContact, setEditingContact] = useState<Contact | null>(null);
  const [viewingContact, setViewingContact] = useState<Contact | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategoryFilter, setSelectedCategoryFilter] = useState<string>('all');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // Loading states
  const [isLoading, setIsLoading] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  // Permission Checks
  const canManageContacts = userRole === 'editor' || userRole === 'admin';
  const canManageSystem = userRole === 'admin';

  const fetchContacts = async () => {
    setIsLoading(true);
    try {
      const data = await DataService.getContacts();
      setContacts(data);

      // Update categories based on actual data
      DataService.syncCategoriesFromData(data);
      setCategories(DataService.getCategories());
    } catch (error) {
      console.error("Failed to fetch contacts", error);
      alert("ไม่สามารถดึงข้อมูลได้ กรุณาลองใหม่อีกครั้ง");
    } finally {
      setIsLoading(false);
    }
  };

  // Check Local Storage for Auth
  useEffect(() => {
    const savedUserJson = localStorage.getItem('pr_app_user');
    if (savedUserJson) {
      try {
        const user = JSON.parse(savedUserJson) as User;
        setCurrentUser(user);
        setUserRole(user.role);
        setIsAuthenticated(true);
      } catch (e) {
        localStorage.removeItem('pr_app_user');
      }
    }
  }, []);

  // Load data when authenticated
  useEffect(() => {
    if (isAuthenticated) {
      // Ensure we load data whenever authentication is confirmed
      fetchContacts();
      setCategories(DataService.getCategories());
    }
  }, [isAuthenticated]);

  // Close sidebar when view changes on mobile
  useEffect(() => {
    setIsSidebarOpen(false);
  }, [view]);

  const handleLoginSuccess = (user: User) => {
    setCurrentUser(user);
    setUserRole(user.role);
    setIsAuthenticated(true);
    // Reset view to dashboard when logging in
    setView('dashboard');

    // Persist login state
    localStorage.setItem('pr_app_user', JSON.stringify(user));

    // Log login activity
    DataService.logActivity(user, 'เข้าสู่ระบบ', 'Login สำเร็จ');
  };

  const handleLogout = () => {
    if (currentUser) {
        DataService.logActivity(currentUser, 'ออกจากระบบ', 'Logout สำเร็จ');
    }
    setIsAuthenticated(false);
    setUserRole('viewer');
    setCurrentUser(null);
    localStorage.removeItem('pr_app_user');
    setView('dashboard');
    setViewingContact(null);
    setEditingContact(null);
    setContacts([]); // Clear contacts on logout
  };

  // Filter contacts
  const filteredContacts = useMemo(() => {
    return contacts.filter(contact => {
      const matchesSearch = 
        contact.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        contact.organization.toLowerCase().includes(searchTerm.toLowerCase()) ||
        contact.position.toLowerCase().includes(searchTerm.toLowerCase()) ||
        contact.address.province.toLowerCase().includes(searchTerm.toLowerCase());

      const matchesCategory = selectedCategoryFilter === 'all' || contact.type === selectedCategoryFilter;

      return matchesSearch && matchesCategory;
    });
  }, [contacts, searchTerm, selectedCategoryFilter]);

  const handleSaveContact = async (contact: Contact) => {
    if (!canManageContacts || !currentUser) return;
    setIsSaving(true);
    try {
      await DataService.saveContact(contact, currentUser);
      setTimeout(async () => {
          await fetchContacts();
      }, 1500);

      setView('dashboard');
      setEditingContact(null);
    } catch (error) {
      alert("เกิดข้อผิดพลาดในการบันทึกข้อมูล");
    } finally {
      setIsSaving(false);
    }
  };

  const handleDeleteContact = async (id: string) => {
    if (!canManageContacts || !currentUser) return;

    const contactToDelete = contacts.find(c => c.id === id);
    if (!contactToDelete) return;

    if (confirm('ยืนยันการลบข้อมูลนี้? (การลบจะส่งผลต่อฐานข้อมูลโดยตรง)')) {
      setIsLoading(true);
      try {
        await DataService.deleteContact(id, contactToDelete.name, currentUser);
        setTimeout(async () => {
             await fetchContacts();
        }, 1500);

      } catch (error) {
        alert("เกิดข้อผิดพลาดในการลบข้อมูล");
        setIsLoading(false);
      }
    }
  };

  const handleEditContact = (contact: Contact) => {
     if (!canManageContacts) return;
     setEditingContact(contact);
     setView('add');
  };

  const handleViewContact = (contact: Contact) => {
    setViewingContact(contact);
    setView('details');
  };

  const handleAddCategory = (name: string) => {
    if (!canManageSystem || !currentUser) return;
    DataService.addCategory(name, currentUser);
    setCategories(DataService.getCategories());
  };

  const handleDeleteCategory = (id: string) => {
    if (!canManageSystem || !currentUser) return;
    const cat = categories.find(c => c.id === id);
    if (confirm(`ยืนยันการลบหมวดหมู่ "${cat?.name}"?`)) {
      DataService.deleteCategory(id, cat?.name || '', currentUser);
      setCategories(DataService.getCategories());
    }
  };

  const handleExportCSV = () => {
    if (!currentUser) return;
    const csvContent = DataService.exportToCSV(contacts, currentUser);
    const blob = new Blob([new Uint8Array([0xEF, 0xBB, 0xBF]), csvContent], { type: 'text/csv;charset=utf-8;' }); 
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `pr_contacts_${new Date().toISOString().slice(0,10)}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- RENDER LOGIN SCREEN ---
  if (!isAuthenticated) {
    return <LoginScreen onLogin={handleLoginSuccess} />;
  }

  // --- RENDER MAIN APP ---
  return (
    <div className="flex h-screen bg-gray-50 overflow-hidden">

      {/* Mobile Sidebar Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 md:hidden transition-opacity"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Sidebar Navigation */}
      <aside className={`
        fixed md:static inset-y-0 left-0 z-50 w-64 bg-primary text-white flex flex-col flex-shrink-0 transition-transform duration-300 ease-in-out md:translate-x-0
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="p-6 border-b border-blue-800 flex justify-between items-center">
          <div>
            <h1 className="text-2xl font-bold tracking-tight">PR Manager</h1>
            <div className="flex items-center gap-2 mt-2 text-blue-200 text-sm bg-blue-800/50 py-1 px-2 rounded-md w-fit">
                {userRole === 'admin' ? <Lock size={14} className="text-red-300" /> : 
                 userRole === 'editor' ? <ShieldCheck size={14} className="text-orange-300" /> : 
                 <Shield size={14} className="text-green-300" />}
                <span className="capitalize">{currentUser?.name || userRole}</span>
            </div>
          </div>
          <button 
            onClick={() => setIsSidebarOpen(false)} 
            className="md:hidden text-blue-200 hover:text-white p-1"
          >
            <X size={24} />
          </button>
        </div>

        <nav className="p-4 space-y-2 flex-1 overflow-y-auto">
          <button 
            onClick={() => { setView('dashboard'); setViewingContact(null); }}
            className={`w-full flex items-center p-3 rounded-lg transition-colors ${view === 'dashboard' || view === 'details' ? 'bg-blue-800' : 'hover:bg-blue-700'}`}
          >
            <LayoutDashboard size={20} className="mr-3" />
            <span>รายชื่อผู้ติดต่อ</span>
          </button>

          <button 
            onClick={() => setView('analytics')}
            className={`w-full flex items-center p-3 rounded-lg transition-colors ${view === 'analytics' ? 'bg-blue-800' : 'hover:bg-blue-700'}`}
          >
            <PieChart size={20} className="mr-3" />
            <span>ภาพรวมข้อมูล</span>
          </button>

          {/* Contact Management (Editor & Admin) */}
          {canManageContacts && (
            <>
                <div className="pt-4 pb-2 px-3 text-xs uppercase text-blue-300 font-semibold tracking-wider">
                    จัดการข้อมูล
                </div>
                <button 
                    onClick={() => { setEditingContact(null); setView('add'); }}
                    className={`w-full flex items-center p-3 rounded-lg transition-colors ${view === 'add' ? 'bg-blue-800' : 'hover:bg-blue-700'}`}
                >
                    <Plus size={20} className="mr-3" />
                    <span>เพิ่มข้อมูล</span>
                </button>
            </>
          )}

          {/* System Settings (Admin Only) */}
          {canManageSystem && (
             <>
                <div className="pt-4 pb-2 px-3 text-xs uppercase text-blue-300 font-semibold tracking-wider">
                    ผู้ดูแลระบบ
                </div>
                <button 
                    onClick={() => setView('categories')}
                    className={`w-full flex items-center p-3 rounded-lg transition-colors ${view === 'categories' ? 'bg-blue-800' : 'hover:bg-blue-700'}`}
                >
                    <Settings size={20} className="mr-3" />
                    <span>จัดการหมวดหมู่</span>
                </button>
                <button 
                    onClick={() => setView('users')}
                    className={`w-full flex items-center p-3 rounded-lg transition-colors ${view === 'users' ? 'bg-blue-800' : 'hover:bg-blue-700'}`}
                >
                    <UserCog size={20} className="mr-3" />
                    <span>จัดการผู้ใช้งาน</span>
                </button>
                <button 
                    onClick={() => setView('logs')}
                    className={`w-full flex items-center p-3 rounded-lg transition-colors ${view === 'logs' ? 'bg-blue-800' : 'hover:bg-blue-700'}`}
                >
                    <History size={20} className="mr-3" />
                    <span>ประวัติการใช้งาน</span>
                </button>
             </>
          )}
        </nav>

        <div className="p-4 mt-auto border-t border-blue-800 space-y-2">
           <button 
                onClick={handleLogout}
                className="w-full flex items-center p-2 rounded-lg text-blue-200 hover:text-white hover:bg-blue-800 transition-colors"
            >
                <LogOut size={20} className="mr-3" />
                <span>ออกจากระบบ</span>
            </button>

          {/* Link visible to Editor and Admin */}
          {(canManageContacts) && (
            <a 
              href={GOOGLE_SHEET_URL} 
              target="_blank" 
              rel="noreferrer"
              className="flex items-center p-2 text-sm text-blue-200 hover:text-white transition-colors"
            >
              <ExternalLink size={16} className="mr-2" />
              เปิด Google Sheet
            </a>
          )}
        </div>
      </aside>

      {/* Main Content Wrapper */}
      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">

        {/* Mobile Header */}
        <header className="md:hidden bg-white border-b border-gray-200 p-4 flex items-center justify-between flex-shrink-0 z-30">
           <div className="font-bold text-gray-700 flex items-center gap-2">
              <Users size={20} className="text-primary"/>
              <span>PR Manager</span>
           </div>
           <button 
              onClick={() => setIsSidebarOpen(true)}
              className="p-2 text-gray-600 hover:bg-gray-100 rounded-lg transition-colors"
           >
              <Menu size={24} />
           </button>
        </header>

        {/* Loading Overlay */}
        {(isLoading || isSaving) && (
          <div className="fixed inset-0 bg-black/20 backdrop-blur-sm z-50 flex items-center justify-center">
            <div className="bg-white p-6 rounded-xl shadow-xl flex items-center space-x-4">
              <div className="w-6 h-6 border-4 border-primary border-t-transparent rounded-full animate-spin"></div>
              <span className="text-gray-700 font-medium">
                {isSaving ? 'กำลังบันทึกข้อมูล...' : 'กำลังโหลดข้อมูล...'}
              </span>
            </div>
          </div>
        )}

        {/* Scrollable Main Area */}
        <main className="flex-1 overflow-auto p-4 md:p-8 scroll-smooth">

          {view === 'dashboard' && (
            <div className="max-w-7xl mx-auto space-y-6">
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <h2 className="text-2xl font-bold text-gray-800">รายชื่อผู้ติดต่อทั้งหมด</h2>
                <div className="flex flex-wrap gap-2">
                  <Button variant="secondary" onClick={fetchContacts} title="อัปเดตข้อมูล">
                    <RefreshCw size={18} className={isLoading ? "animate-spin" : ""} />
                  </Button>
                  <Button variant="secondary" onClick={handleExportCSV}>
                    <Download size={18} className="mr-2" />
                    <span className="hidden sm:inline">Export CSV</span>
                    <span className="sm:hidden">CSV</span>
                  </Button>
                  {canManageContacts && (
                    <Button onClick={() => { setEditingContact(null); setView('add'); }}>
                        <Plus size={18} className="mr-2" />
                        เพิ่มข้อมูล
                    </Button>
                  )}
                </div>
              </div>

              {/* Filters and View Toggle */}
              <div className="flex flex-col md:flex-row gap-4 justify-between items-end md:items-center">
                <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex flex-col md:flex-row gap-4 flex-1 w-full">
                  <div className="relative flex-1">
                    <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={20} />
                    <input
                      type="text"
                      placeholder="ค้นหา ชื่อ, หน่วยงาน..."
                      className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary focus:border-transparent"
                      value={searchTerm}
                      onChange={(e) => setSearchTerm(e.target.value)}
                    />
                  </div>
                  <select 
                    className="p-2 border border-gray-300 rounded-lg bg-white w-full md:w-auto md:min-w-[200px]"
                    value={selectedCategoryFilter}
                    onChange={(e) => setSelectedCategoryFilter(e.target.value)}
                  >
                    <option value="all">ทุกหมวดหมู่</option>
                    {categories.map(c => (
                      <option key={c.id} value={c.name}>{c.name}</option>
                    ))}
                  </select>
                </div>

                <div className="flex bg-white p-1 rounded-lg border border-gray-200 shadow-sm shrink-0 h-[58px] items-center">
                   <button 
                      onClick={() => setViewMode('table')}
                      className={`p-2.5 rounded-md transition-colors ${viewMode === 'table' ? 'bg-blue-50 text-primary' : 'text-gray-400 hover:text-gray-600'}`}
                      title="มุมมองตาราง"
                   >
                      <LayoutList size={22} />
                   </button>
                   <button 
                      onClick={() => setViewMode('grid')}
                      className={`p-2.5 rounded-md transition-colors ${viewMode === 'grid' ? 'bg-blue-50 text-primary' : 'text-gray-400 hover:text-gray-600'}`}
                      title="มุมมองการ์ด"
                   >
                      <LayoutGrid size={22} />
                   </button>
                </div>
              </div>

              {/* Content Display */}
              {viewMode === 'grid' ? (
                // GRID VIEW
