const CATEGORIES_KEY = 'pr_categories_data';
const USERS_KEY = 'pr_users_data';
const LOGS_KEY = 'pr_activity_logs';

// Default Admin remains for initial access
const DEFAULT_ADMIN: User = { 
  id: '1', 
  username: 'Urassayawan.je', 
  password: 'Mira.237', 
  name: 'System Admin', 
